class AuthMiddleware:
    def __init__(self):
        self.validator = JwtValidator(required_scopes=['api:read'])

    def __call__(self, request, next_handler):
        # HOTFIX: enforce strict token expiry check before validator
        token = extract_token(request)
        if not token or token_expiration(token) < now():
            raise UnauthorizedError('expired or missing token')
        claims = self.validator.validate(token)
        request.user = claims.sub
        return next_handler(request)

